// Compose audit-trail + Solve-event context
const context = $('MongoDB — Sensor context laatste 10 min').all().map(i => i.json);
const batch = $('MongoDB — Huidige Batch ID').first().json;
const shift = $('ERP — Dienstdoende QA-engineer').first().json;

const temp_samples = context.filter(c => c.topic.endsWith('/temperature_C')).map(c => c.value);
const regen_samples = context.filter(c => c.topic.endsWith('/regen_efficiency_pct')).map(c => c.value);
const hold_samples = context.filter(c => c.topic.endsWith('/hold_time_s')).map(c => c.value);

const min_temp = Math.min(...temp_samples);
const min_regen = Math.min(...regen_samples);
const current_hold = hold_samples[0];
const divert_duration_sec = temp_samples.filter(t => t < 71.5).length;

// Likely root cause heuristic (regen-eff drop → temperature drop)
let root_cause = 'unknown';
if (min_regen < 80) root_cause = 'regen_efficiency_degradation';
else if (current_hold < 14.5) root_cause = 'hold_time_short';
else root_cause = 'upstream_supply_disturbance';

return {
  json: {
    solve_id: 'MAIN-SOLVE',
    event_type: 'htst_under_pasteurization',
    timestamp: new Date().toISOString(),
    batch_id: batch.value,
    unit_id: 'HTST-01',
    current_temp_C: temp_samples[0],
    min_temp_C_10min: min_temp,
    min_regen_eff_pct: min_regen,
    current_hold_time_s: current_hold,
    divert_duration_sec: divert_duration_sec,
    likely_root_cause: root_cause,
    qa_engineer: shift.name,
    qa_engineer_teams_id: shift.teams_id,
    regulatory_threshold_C: 71.7,
    alarm_threshold_C: 71.5,
    regulation: 'EU Reg. 853/2004 Annex III Section IX Ch.II',
    audit_required: true,
    ack_deadline: new Date(Date.now() + 15*60*1000).toISOString()
  }
};
